mapper.update:
UPDATE club_manages
SET    CLUB_TITLE  = #{clubTitle},
       LOCATION    = #{location},
       MAX_MEMBERS = #{maxMembers},
       DESCRIPTION = #{description}
WHERE  CLUB_ID     = #{clubId}

UPDATE club_members
SET    BIRTH_YEAR  = #{birthYear},
       GENDER      = #{gender},
       ADDR1LEVEL  = #{addr1Level},
       ADDR2LEVEL  = #{addr2Level},
       ADDR3LEVEL  = #{addr3Level}
WHERE  CLUB_ID = #{clubId}
  AND  USER_ID = #{userId}

UPDATE club_members
SET    USER_NAME   = #{userName},
       GENDER      = #{gender},
       BIRTH_YEAR  = #{birthYear},
       ADDR1LEVEL  = #{addr1Level},
       ADDR2LEVEL  = #{addr2Level},
       ADDR3LEVEL  = #{addr3Level}
WHERE  MEMBER_SEQ  = #{memberSeq}
  AND  CLUB_ID     = #{clubId}

UPDATE club_members
SET    STATUS = 'N'
WHERE  MEMBER_SEQ = #{memberSeq}

mapper.select:
SELECT COUNT(*)
FROM   club_members
WHERE  CLUB_ID   = #{clubId}
AND  USER_NAME = #{userName}
AND  STATUS    = 'Y'

    AND  MEMBER_SEQ <> #{memberSeq}

